SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, make_date(TRY_CAST("YEAR" AS INTEGER), TRY_CAST("MONTH_NUM" AS INTEGER), 1) AS date, NULLIF("APT_ICAO", '') AS apt_icao, NULLIF("APT_NAME", '') AS apt_name, NULLIF("STATE_NAME", '') AS state_name, NULLIF("MONTH_MON", '') AS month_mon, NULLIF("AIRPORT_NAME", '') AS airport_name, TRY_CAST("NBR_FLIGHTS_DESCENT" AS DOUBLE) AS nbr_flights_descent, TRY_CAST("TOT_DIST_LEVEL_NM_DESCENT" AS DOUBLE) AS tot_dist_level_nm_descent, TRY_CAST("TOT_DIST_LVL_NM_DESC_BLW_70" AS DOUBLE) AS tot_dist_lvl_nm_desc_blw_70, TRY_CAST("TOT_TIME_LEVEL_SECONDS_DESCENT" AS DOUBLE) AS tot_time_level_seconds_descent, TRY_CAST("TOT_TIME_LEVEL_SEC_DESC_BLW_70" AS DOUBLE) AS tot_time_level_sec_desc_blw_70, TRY_CAST("MEDIAN_CDO_ALT" AS DOUBLE) AS median_cdo_alt, TRY_CAST("NBR_CDO_FLIGHTS" AS DOUBLE) AS nbr_cdo_flights, TRY_CAST("NBR_CDO_FLIGHTS_BELOW_7000" AS DOUBLE) AS nbr_cdo_flights_below_7000, TRY_CAST("TOT_DELTA_CO2_KG_DESCENT" AS DOUBLE) AS tot_delta_co2_kg_descent, TRY_CAST("TOT_DELTA_CO2_KG_DESC_BLW_70" AS DOUBLE) AS tot_delta_co2_kg_desc_blw_70, TRY_CAST("NBR_FLIGHTS_CLIMB" AS DOUBLE) AS nbr_flights_climb, TRY_CAST("TOT_DIST_LEVEL_NM_CLIMB" AS DOUBLE) AS tot_dist_level_nm_climb, TRY_CAST("TOT_DIST_LVL_NM_CLIMB_BLW_100" AS DOUBLE) AS tot_dist_lvl_nm_climb_blw_100, TRY_CAST("TOT_TIME_LEVEL_SECONDS_CLIMB" AS DOUBLE) AS tot_time_level_seconds_climb, TRY_CAST("TOT_TIME_LVL_SEC_CLIMB_BLW_100" AS DOUBLE) AS tot_time_lvl_sec_climb_blw_100, TRY_CAST("MEDIAN_CCO_ALT" AS DOUBLE) AS median_cco_alt, TRY_CAST("NBR_CCO_FLIGHTS" AS DOUBLE) AS nbr_cco_flights, TRY_CAST("NBR_CCO_FLIGHTS_BELOW_10000" AS DOUBLE) AS nbr_cco_flights_below_10000, TRY_CAST("TOT_DELTA_CO2_KG_CLIMB" AS DOUBLE) AS tot_delta_co2_kg_climb, TRY_CAST("TOT_DELTA_CO2_KG_CLIMB_BLW_100" AS DOUBLE) AS tot_delta_co2_kg_climb_blw_100 FROM "eurocontrol-vertical-flight-efficiency") WHERE date IS NOT NULL
